queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?metric_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:metric_id ?cg . ?child a :Metrics ; p:metric_id ?cg . ?l p:financial_analyst_id ?pg . ?parent a :Financial_Analysts ; p:id ?pg . } GROUP BY ?child }
  ?child p:metric_name ?metric_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Financial_Analysts } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?metric_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:metric_id ?cg . ?child a :Metrics ; p:metric_id ?cg . ?l p:financial_analyst_id ?pg . ?parent a :Financial_Analysts ; p:id ?pg . } GROUP BY ?child }
  ?child p:metric_name ?metric_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Financial_Analysts } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?metric_name WHERE {
  ?financial_analysts_metrics a :Financial_Analysts_Metrics .
  ?metrics a :Metrics .
  ?financial_analysts_metrics p:hasMetrics ?metrics .
  ?financial_analysts a :Financial_Analysts .
  ?financial_analysts_metrics p:hasFinancial_Analysts ?financial_analysts .
  ?financial_analysts p:name ?name .
  ?metrics p:metric_name ?metric_name .
} }
}
